// ============================================================================
// ui_widgets_context_menu.cpp - Context Menu Widget
// ============================================================================
//
// Reusable context menu widget supporting:
// - Regular clickable items with optional icons
// - Separators
// - Submenus with hover delay
// - Checkbox items
// - Keyboard navigation
// ============================================================================

// Extern declarations for blur effect (from platform.cpp)
extern ID2D1DeviceContext* g_d2d_device_context;
extern ID2D1Effect* g_blur_effect;

// ============================================================================
// Menu Item Types
// ============================================================================

enum class MenuItemType : uint8_t {
    Regular,    // Clickable item with label and optional icon
    Separator,  // Thin horizontal line
    Submenu,    // Item that opens nested menu (chevron on right)
    Checkbox,   // Toggleable with checkmark
};

// ============================================================================
// Menu Item Structure
// ============================================================================

struct ContextMenuWidget;

struct MenuItem {
    MenuItemType type = MenuItemType::Regular;
    const wchar_t* label = nullptr;
    const wchar_t* shortcut = nullptr;       // Right-aligned accelerator (e.g., "Ctrl+C")
    MenuItem* submenu_items = nullptr;       // Array of submenu items (for Submenu type)
    size_t submenu_item_count = 0;
    bool checked = false;                    // For Checkbox type
    bool enabled = true;
    void (*on_click)(MenuItem* item, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Internal (set during layout)
    float item_y = 0.0f;                     // Y position within menu
    float item_height = 0.0f;                // Height of this item
};

// ============================================================================
// Context Menu Widget
// ============================================================================

struct ContextMenuWidget : Widget {
    // Content
    MenuItem* items = nullptr;
    size_t item_count = 0;

    // Position & size
    float menu_x = 0.0f;
    float menu_y = 0.0f;
    float menu_width = 0.0f;
    float menu_height = 0.0f;
    float icon_column_width = 0.0f;          // 0 if no icons/checkboxes in menu
    float max_shortcut_width = 0.0f;         // Width of longest shortcut text

    // Text width cache (avoids recreating IDWriteTextLayout on every show)
    static constexpr size_t MAX_CACHED_ITEMS = 32;
    float cached_label_widths[MAX_CACHED_ITEMS] = {};
    float cached_shortcut_widths[MAX_CACHED_ITEMS] = {};
    MenuItem* cached_items = nullptr;        // Pointer to items when cache was built
    size_t cached_item_count = 0;            // Item count when cache was built

    // State
    int hovered_index = -1;
    int pressed_index = -1;
    int keyboard_focus_index = -1;
    bool visible = false;

    // Submenu handling
    ContextMenuWidget* active_submenu = nullptr;
    ContextMenuWidget* parent_menu = nullptr;
    int submenu_parent_index = -1;
    uint64_t submenu_hover_start = 0;

    // Callbacks
    void (*on_dismiss)(ContextMenuWidget* menu, void* user_data) = nullptr;
    void* dismiss_user_data = nullptr;

    // Animation state
    enum class AnimState : uint8_t { Closed, Opening, Open, Closing };
    AnimState anim_state = AnimState::Closed;
    float anim_progress = 0.0f;      // 0→1 normalized time
    float anim_scale = 0.0f;         // Current scale (0→1, can overshoot)
    float anim_opacity = 0.0f;       // Current opacity (0→1)
    float anim_velocity = 0.0f;      // For spring physics
    float click_origin_x = 0.0f;     // Scale origin (click point)
    float click_origin_y = 0.0f;
    float content_offset_y = 0.0f;   // Content slide offset (starts negative, animates to 0)
    float content_blur = 0.0f;       // Blur radius (starts at max, animates to 0)
    bool is_submenu = false;         // For faster submenu timing
    int animation_frame_count = 0;   // Safety timeout counter
    static constexpr int MAX_ANIMATION_FRAMES = 120;  // ~2 seconds at 60fps

    // Cached blur render target (recreated only when menu dimensions change)
    ID2D1BitmapRenderTarget* cached_blur_target = nullptr;
    ID2D1SolidColorBrush* cached_blur_brush = nullptr;
    float cached_blur_width = 0.0f;
    float cached_blur_height = 0.0f;

    // Constructor
    ContextMenuWidget() {
        debug_name = "ContextMenu";
        flags = WidgetFlags::Visible | WidgetFlags::Enabled | WidgetFlags::Focusable;
    }

    ~ContextMenuWidget() {
        close_submenu();
        cancel_own_animation_registration();
        release_blur_cache();
    }

    // Release cached blur render target resources
    void release_blur_cache() {
        if (cached_blur_brush) {
            cached_blur_brush->Release();
            cached_blur_brush = nullptr;
        }
        if (cached_blur_target) {
            cached_blur_target->Release();
            cached_blur_target = nullptr;
        }
        cached_blur_width = 0.0f;
        cached_blur_height = 0.0f;
    }

    // ========================================================================
    // Public API
    // ========================================================================

    void show(float x, float y, MenuItem* menu_items, size_t count) {
        // Store click origin BEFORE any position adjustment (for animation)
        click_origin_x = x;
        click_origin_y = y;

        items = menu_items;
        item_count = count;
        menu_x = x;
        menu_y = y;

        // Reset state
        hovered_index = -1;
        pressed_index = -1;
        keyboard_focus_index = -1;
        close_submenu();

        // Calculate dimensions
        calculate_dimensions();

        // Adjust position to stay on screen
        adjust_position_to_screen();

        // Update widget rect
        rect.x = menu_x;
        rect.y = menu_y;
        rect.width = menu_width;
        rect.height = menu_height;

        // Start open animation
        anim_state = AnimState::Opening;
        anim_progress = 0.0f;
        anim_scale = 0.0f;
        anim_opacity = 0.0f;
        anim_velocity = 0.0f;  // Let spring restoring force drive the motion
        content_offset_y = -ContextMenu::CONTENT_SLIDE_DISTANCE;  // Start above, slide down
        content_blur = ContextMenu::CONTENT_BLUR_RADIUS;          // Start blurred
        animation_frame_count = 0;  // Reset timeout counter

        // Register with animation scheduler for continuous rendering
        g_animation_scheduler.animation_started();

        visible = true;
        flags |= WidgetFlags::Visible;
        set_dirty();
    }

    void hide() {
        close_submenu();

        if (anim_state == AnimState::Open || anim_state == AnimState::Opening) {
            if (anim_state == AnimState::Open) {
                // Was fully open, now starting close animation
                g_animation_scheduler.animation_started();
            }
            // If Opening: animation already registered, just switch to closing
            // (opening ends when closing completes - one animation_ended() call)

            // Start close animation (fade only)
            anim_state = AnimState::Closing;
            anim_progress = 0.0f;
            // Keep current opacity as starting point for fade
            set_dirty();
        } else {
            // Already closing or closed - finish immediately and balance any
            // outstanding scheduler registration from the closing path.
            force_close_immediate(true);
        }
    }

    void force_close_immediate(bool notify_dismiss) {
        close_submenu();
        cancel_own_animation_registration();
        visible = false;
        flags &= ~WidgetFlags::Visible;
        anim_state = AnimState::Closed;
        anim_progress = 0.0f;
        anim_scale = 1.0f;
        anim_opacity = 0.0f;
        anim_velocity = 0.0f;
        content_offset_y = 0.0f;
        content_blur = 0.0f;
        release_blur_cache();
        if (notify_dismiss && on_dismiss) {
            on_dismiss(this, dismiss_user_data);
        }
        set_dirty();
    }

    // ========================================================================
    // Widget Overrides
    // ========================================================================

    void measure(const LayoutConstraints& constraints) override {
        (void)constraints;
        rect.width = menu_width;
        rect.height = menu_height;
    }

    void layout() override {
        // Layout is done in calculate_dimensions()
    }

    void tick(float dt) override {
        if (anim_state == AnimState::Closed || anim_state == AnimState::Open) return;

        // Safety timeout: force-complete animation if it runs too long (~2 seconds)
        if (++animation_frame_count > MAX_ANIMATION_FRAMES) {
            anim_state = AnimState::Open;
            anim_scale = 1.0f;
            anim_opacity = 1.0f;
            content_offset_y = 0.0f;
            content_blur = 0.0f;
            release_blur_cache();
            g_animation_scheduler.animation_ended();
            set_dirty();
            return;
        }

        if (anim_state == AnimState::Opening) {
            // Opacity fades in quickly (reaches 1.0 before scale settles)
            constexpr float OPACITY_DURATION = 0.20f;  // 200ms
            anim_opacity = fminf(1.0f, anim_opacity + dt / OPACITY_DURATION);

            // Spring physics for scale (analytical solution - frame-rate independent)
            spring_update_windows_style(anim_scale, anim_velocity, 1.0f, dt,
                                        ContextMenu::SPRING_PERIOD, ContextMenu::SPRING_DAMPING_RATIO);

            // Content slide and blur: ease toward 0 (tied to opacity progress)
            content_offset_y = -ContextMenu::CONTENT_SLIDE_DISTANCE * (1.0f - anim_opacity);
            content_blur = ContextMenu::CONTENT_BLUR_RADIUS * (1.0f - anim_opacity);

            // Complete when spring settles AND opacity is done
            if (anim_opacity >= 1.0f && fabsf(anim_scale - 1.0f) < 0.002f && fabsf(anim_velocity) < 0.01f) {
                anim_state = AnimState::Open;
                anim_scale = 1.0f;
                anim_opacity = 1.0f;
                content_offset_y = 0.0f;
                content_blur = 0.0f;
                release_blur_cache();  // Blur animation complete, release cached resources
                g_animation_scheduler.animation_ended();
            }
            set_dirty();
        }
        else if (anim_state == AnimState::Closing) {
            anim_progress += (dt * 1000.0f) / ContextMenu::ANIM_CLOSE_DURATION_MS;
            anim_opacity = 1.0f - anim_progress;

            if (anim_progress >= 1.0f) {
                anim_state = AnimState::Closed;
                visible = false;
                flags &= ~WidgetFlags::Visible;
                release_blur_cache();  // Ensure cache is released on close
                g_animation_scheduler.animation_ended();
                if (on_dismiss) {
                    on_dismiss(this, dismiss_user_data);
                }
            }
            set_dirty();
        }
    }

    // Check if scale differs from 1.0 (within tolerance)
    bool is_scaling() const {
        return anim_scale < 0.999f || anim_scale > 1.001f;
    }

    // Render all menu items to the given context
    void render_all_items(RenderContext& render_ctx) {
        for (size_t i = 0; i < item_count; i++) {
            render_item(render_ctx, items[i], static_cast<int>(i));
        }
    }

    void render(RenderContext& ctx) override {
        if (!visible || !items) return;
        if (anim_state == AnimState::Closed) return;

        // Save current transform
        D2D1_MATRIX_3X2_F old_transform;
        ctx.target->GetTransform(&old_transform);

        // Apply scale transform around click origin (for open animation)
        if (is_scaling()) {
            D2D1_MATRIX_3X2_F scale_transform =
                D2D1::Matrix3x2F::Translation(-click_origin_x, -click_origin_y) *
                D2D1::Matrix3x2F::Scale(anim_scale, anim_scale) *
                D2D1::Matrix3x2F::Translation(click_origin_x, click_origin_y);
            ctx.target->SetTransform(old_transform * scale_transform);
        }

        // Apply opacity via brush
        ctx.brush->SetOpacity(anim_opacity);

        D2D1_RECT_F menu_rect = D2D1::RectF(
            menu_x, menu_y,
            menu_x + menu_width, menu_y + menu_height
        );

        // Draw shadow
        ctx.draw_tooltip_shadow(menu_rect, ContextMenu::CORNER_RADIUS);

        // Draw background
        ctx.fill_rounded_rect(menu_rect, ContextMenu::CORNER_RADIUS, ContextMenu::BG);

        // Draw border
        ctx.brush->SetColor(color_from_argb(ContextMenu::BORDER));
        D2D1_ROUNDED_RECT border_rr = { menu_rect, ContextMenu::CORNER_RADIUS, ContextMenu::CORNER_RADIUS };
        ctx.target->DrawRoundedRectangle(border_rr, ctx.brush, 1.0f);

        // Clip to menu interior
        D2D1_RECT_F content_rect = D2D1::RectF(
            menu_x + 1.0f, menu_y + ContextMenu::PADDING_V,
            menu_x + menu_width - 1.0f, menu_y + menu_height - ContextMenu::PADDING_V
        );
        ctx.push_clip(content_rect);

        // Apply inverse scale + slide offset so content stays at full size during container scale
        D2D1_MATRIX_3X2_F container_transform;
        ctx.target->GetTransform(&container_transform);
        if (anim_scale > 0.01f && (is_scaling() || content_offset_y != 0.0f)) {
            float inv_scale = 1.0f / anim_scale;
            float cx = menu_x + menu_width * 0.5f;
            float cy = menu_y + menu_height * 0.5f;
            D2D1_MATRIX_3X2_F content_transform =
                D2D1::Matrix3x2F::Translation(-cx, -cy) *
                D2D1::Matrix3x2F::Scale(inv_scale, inv_scale) *
                D2D1::Matrix3x2F::Translation(cx, cy + content_offset_y);
            ctx.target->SetTransform(container_transform * content_transform);
        }

        // Render items (with optional blur during animation)
        bool use_blur = content_blur > 0.1f && g_d2d_device_context && g_blur_effect;

        if (use_blur) {
            render_items_with_blur(ctx);
        } else {
            render_all_items(ctx);
        }

        // Restore container transform before popping clip
        ctx.target->SetTransform(container_transform);
        ctx.pop_clip();

        // Restore state
        ctx.brush->SetOpacity(1.0f);
        ctx.target->SetTransform(old_transform);
    }

    // Render items with Gaussian blur effect (used during open animation)
    void render_items_with_blur(RenderContext& ctx) {
        // Check if we need to recreate the cached render target (dimensions changed or not created)
        if (!cached_blur_target || cached_blur_width != menu_width || cached_blur_height != menu_height) {
            release_blur_cache();

            D2D1_SIZE_F bitmap_size = D2D1::SizeF(menu_width, menu_height);
            HRESULT hr = ctx.target->CreateCompatibleRenderTarget(bitmap_size, &cached_blur_target);

            if (FAILED(hr) || !cached_blur_target) {
                render_all_items(ctx);  // Fallback to direct rendering
                return;
            }

            cached_blur_target->CreateSolidColorBrush(D2D1::ColorF(D2D1::ColorF::White), &cached_blur_brush);

            if (!cached_blur_brush) {
                release_blur_cache();
                render_all_items(ctx);
                return;
            }

            cached_blur_width = menu_width;
            cached_blur_height = menu_height;
        }

        // Render items to offscreen bitmap
        cached_blur_target->BeginDraw();
        cached_blur_target->Clear(D2D1::ColorF(0, 0, 0, 0));
        // Shift menu content into offscreen bitmap: (menu_x, menu_y + PADDING_V) in window
        // space maps to (0, 0) in bitmap space. This compensates for the vertical padding
        // added when drawing the blurred image back at origin (menu_x, menu_y + PADDING_V).
        cached_blur_target->SetTransform(D2D1::Matrix3x2F::Translation(-menu_x, -menu_y - ContextMenu::PADDING_V));

        RenderContext bitmap_ctx;
        bitmap_ctx.target = cached_blur_target;
        bitmap_ctx.brush = cached_blur_brush;
        render_all_items(bitmap_ctx);

        cached_blur_target->EndDraw();

        // Apply blur and draw
        ID2D1Bitmap* bitmap = nullptr;
        cached_blur_target->GetBitmap(&bitmap);

        if (bitmap) {
            g_blur_effect->SetInput(0, bitmap);
            g_blur_effect->SetValue(D2D1_GAUSSIANBLUR_PROP_STANDARD_DEVIATION, content_blur);
            D2D1_POINT_2F origin = D2D1::Point2F(menu_x, menu_y + ContextMenu::PADDING_V);
            g_d2d_device_context->DrawImage(g_blur_effect, origin);
            bitmap->Release();
        }
        // Note: cached_blur_target and cached_blur_brush are retained for reuse
        // They will be released when animation completes or menu closes
    }

    bool on_mouse_move(float x, float y) override {
        if (!visible) return false;
        if (anim_state != AnimState::Open) return true;  // Skip hover tracking during animation

        // Convert to menu-relative coordinates
        float local_x = x;
        float local_y = y;

        int new_hovered = hit_test_item(local_x, local_y);

        if (new_hovered != hovered_index) {
            hovered_index = new_hovered;
            submenu_hover_start = 0;
            set_dirty();
        }

        // Handle submenu hover delay
        if (hovered_index >= 0 && static_cast<size_t>(hovered_index) < item_count) {
            MenuItem& item = items[hovered_index];
            if (item.type == MenuItemType::Submenu && item.enabled) {
                if (hovered_index != submenu_parent_index) {
                    // Different submenu item than currently open
                    if (submenu_hover_start == 0) {
                        submenu_hover_start = GetTickCount64();
                    } else if (GetTickCount64() - submenu_hover_start >= ContextMenu::SUBMENU_DELAY_MS) {
                        open_submenu(hovered_index);
                        submenu_hover_start = 0;
                    }
                }
            } else {
                submenu_hover_start = 0;
                // Close submenu if hovering non-submenu item
                if (active_submenu && hovered_index != submenu_parent_index) {
                    close_submenu();
                }
            }
        }

        return true;  // Consume mouse move when visible
    }

    bool on_mouse_down(float x, float y, int button) override {
        if (!visible) return false;
        if (anim_state != AnimState::Open) return true;  // Block input during animation
        if (button != 0) return true;  // Only handle left click

        // Check if click is inside menu
        if (x < 0 || y < 0 || x >= menu_width || y >= menu_height) {
            // Click outside - close menu
            ContextMenuWidget* root = this;
            while (root->parent_menu) root = root->parent_menu;
            root->hide();
            return true;
        }

        pressed_index = hovered_index;
        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        if (!visible) return false;
        if (anim_state != AnimState::Open) return true;  // Block input during animation
        if (button != 0) return true;

        (void)x; (void)y;

        if (pressed_index == hovered_index && pressed_index >= 0) {
            activate_item(pressed_index);
        }
        pressed_index = -1;
        return true;
    }

    bool on_mouse_leave() override {
        if (!visible) return false;

        // Don't clear hover if we're in a submenu
        if (!active_submenu) {
            hovered_index = -1;
            submenu_hover_start = 0;
            set_dirty();
        }
        return true;
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        if (!visible) return false;
        (void)ctrl; (void)shift; (void)alt;

        switch (vk) {
            case VK_DOWN:
                keyboard_focus_index = find_next_enabled_item(keyboard_focus_index, 1);
                hovered_index = keyboard_focus_index;
                set_dirty();
                return true;

            case VK_UP:
                keyboard_focus_index = find_next_enabled_item(keyboard_focus_index, -1);
                hovered_index = keyboard_focus_index;
                set_dirty();
                return true;

            case VK_RIGHT:
                if (keyboard_focus_index >= 0 &&
                    static_cast<size_t>(keyboard_focus_index) < item_count &&
                    items[keyboard_focus_index].type == MenuItemType::Submenu &&
                    items[keyboard_focus_index].enabled) {
                    open_submenu(keyboard_focus_index);
                    if (active_submenu) {
                        active_submenu->keyboard_focus_index = active_submenu->find_next_enabled_item(-1, 1);
                        active_submenu->hovered_index = active_submenu->keyboard_focus_index;
                        active_submenu->set_dirty();
                    }
                }
                return true;

            case VK_LEFT:
                if (parent_menu) {
                    parent_menu->close_submenu();
                    return true;
                }
                break;

            case VK_RETURN:
            case VK_SPACE:
                if (keyboard_focus_index >= 0) {
                    activate_item(keyboard_focus_index);
                }
                return true;

            case VK_ESCAPE:
                if (parent_menu) {
                    parent_menu->close_submenu();
                } else {
                    hide();
                }
                return true;
        }

        return false;
    }

private:
    // ========================================================================
    // Internal Methods
    // ========================================================================

    void cancel_own_animation_registration() {
        if (anim_state == AnimState::Opening || anim_state == AnimState::Closing) {
            g_animation_scheduler.animation_ended();
        }
    }

    void calculate_dimensions() {
        if (!items || item_count == 0) {
            menu_width = ContextMenu::MIN_WIDTH;
            menu_height = ContextMenu::PADDING_V * 2;
            return;
        }

        // Check if any items need icon column (icons or checkboxes)
        bool has_icons_or_checks = false;
        for (size_t i = 0; i < item_count; i++) {
            if (items[i].type == MenuItemType::Checkbox) {
                has_icons_or_checks = true;
                break;
            }
        }
        icon_column_width = has_icons_or_checks ? ContextMenu::ICON_COLUMN_WIDTH : 0.0f;

        // Check if we can use cached text widths
        bool cache_valid = (cached_items == items && cached_item_count == item_count);

        // Calculate max label and shortcut widths (using cache when valid)
        float max_label_width = 0.0f;
        max_shortcut_width = 0.0f;

        for (size_t i = 0; i < item_count; i++) {
            MenuItem& item = items[i];
            if (item.type == MenuItemType::Separator) continue;

            float label_width = 0.0f;
            float shortcut_width = 0.0f;

            // Use cache if valid and within bounds, otherwise measure
            if (cache_valid && i < MAX_CACHED_ITEMS) {
                label_width = cached_label_widths[i];
                shortcut_width = cached_shortcut_widths[i];
            } else {
                // Measure label width
                if (item.label && g_text_format_body) {
                    IDWriteTextLayout* layout = nullptr;
                    g_dwrite_factory->CreateTextLayout(
                        item.label,
                        static_cast<UINT32>(wcslen(item.label)),
                        g_text_format_body,
                        1000.0f, 100.0f,
                        &layout
                    );
                    if (layout) {
                        DWRITE_TEXT_METRICS metrics;
                        layout->GetMetrics(&metrics);
                        label_width = metrics.width;
                        layout->Release();
                    }
                }

                // Measure shortcut width
                if (item.shortcut && g_text_format_body) {
                    IDWriteTextLayout* layout = nullptr;
                    g_dwrite_factory->CreateTextLayout(
                        item.shortcut,
                        static_cast<UINT32>(wcslen(item.shortcut)),
                        g_text_format_body,
                        1000.0f, 100.0f,
                        &layout
                    );
                    if (layout) {
                        DWRITE_TEXT_METRICS metrics;
                        layout->GetMetrics(&metrics);
                        shortcut_width = metrics.width;
                        layout->Release();
                    }
                }

                // Store in cache if within bounds
                if (i < MAX_CACHED_ITEMS) {
                    cached_label_widths[i] = label_width;
                    cached_shortcut_widths[i] = shortcut_width;
                }
            }

            max_label_width = fmaxf(max_label_width, label_width);
            max_shortcut_width = fmaxf(max_shortcut_width, shortcut_width);

            // Add space for submenu chevron
            if (item.type == MenuItemType::Submenu) {
                max_shortcut_width = fmaxf(max_shortcut_width, ContextMenu::CHEVRON_SIZE + ContextMenu::HOVER_INSET);
            }
        }

        // Update cache tracking
        cached_items = items;
        cached_item_count = item_count;

        // Calculate menu width
        menu_width = ContextMenu::PADDING_H * 2 +
                     icon_column_width +
                     max_label_width +
                     (max_shortcut_width > 0 ? ContextMenu::SHORTCUT_SPACING + max_shortcut_width : 0);

        menu_width = fmaxf(ContextMenu::MIN_WIDTH, fminf(ContextMenu::MAX_WIDTH, menu_width));

        // Calculate height and item positions
        float y = ContextMenu::PADDING_V;
        for (size_t i = 0; i < item_count; i++) {
            MenuItem& item = items[i];
            item.item_y = y;

            if (item.type == MenuItemType::Separator) {
                item.item_height = ContextMenu::SEPARATOR_HEIGHT;
            } else {
                item.item_height = ContextMenu::ITEM_HEIGHT;
            }
            y += item.item_height;
        }

        menu_height = y + ContextMenu::PADDING_V;
    }

    void adjust_position_to_screen() {
        // Get screen size from render target
        if (!g_render_target) return;
        D2D1_SIZE_F screen_size = g_render_target->GetSize();

        // Adjust horizontal
        if (menu_x + menu_width > screen_size.width) {
            if (parent_menu) {
                // Flip to left side of parent
                menu_x = parent_menu->menu_x - menu_width + ContextMenu::SUBMENU_OFFSET_X;
            } else {
                menu_x = screen_size.width - menu_width;
            }
        }
        if (menu_x < 0) menu_x = 0;

        // Adjust vertical
        if (menu_y + menu_height > screen_size.height) {
            menu_y = screen_size.height - menu_height;
        }
        if (menu_y < 0) menu_y = 0;
    }

    int hit_test_item(float x, float y) {
        if (x < 0 || y < 0 || x >= menu_width || y >= menu_height) {
            return -1;
        }

        for (size_t i = 0; i < item_count; i++) {
            MenuItem& item = items[i];
            if (item.type == MenuItemType::Separator) continue;

            if (y >= item.item_y && y < item.item_y + item.item_height) {
                return static_cast<int>(i);
            }
        }

        return -1;
    }

    void render_item(RenderContext& ctx, const MenuItem& item, int index) {
        float item_x = menu_x;
        float item_y = menu_y + item.item_y;

        if (item.type == MenuItemType::Separator) {
            // Draw separator line
            float line_y = item_y + ContextMenu::SEPARATOR_HEIGHT / 2.0f;
            ctx.draw_line(
                item_x + ContextMenu::SEPARATOR_INSET,
                line_y,
                item_x + menu_width - ContextMenu::PADDING_H,
                line_y,
                ContextMenu::SEPARATOR,
                1.0f
            );
            return;
        }

        // Draw hover highlight
        bool is_hovered = (index == hovered_index);
        bool is_disabled = !item.enabled;

        if (is_hovered && !is_disabled) {
            D2D1_RECT_F hover_rect = D2D1::RectF(
                item_x + ContextMenu::HOVER_INSET,
                item_y,
                item_x + menu_width - ContextMenu::HOVER_INSET,
                item_y + item.item_height
            );
            ctx.fill_rounded_rect(hover_rect, ContextMenu::HOVER_CORNER_RADIUS, ContextMenu::HOVER_BG);
        }

        float text_x = item_x + ContextMenu::PADDING_H + icon_column_width;
        float text_y = item_y;

        // Draw checkbox checkmark (if checkbox type and checked)
        if (item.type == MenuItemType::Checkbox && item.checked) {
            render_checkmark(ctx, item_x + ContextMenu::PADDING_H, item_y);
        }

        // Draw label
        if (item.label) {
            D2D1_RECT_F label_rect = D2D1::RectF(
                text_x,
                text_y,
                item_x + menu_width - ContextMenu::PADDING_H - ContextMenu::SHORTCUT_SPACING,
                text_y + item.item_height
            );

            uint32_t text_color = is_disabled ? ContextMenu::TEXT_DISABLED : ContextMenu::TEXT;
            ctx.draw_text(item.label, wcslen(item.label), g_text_format_body, label_rect, text_color);
        }

        // Draw shortcut or chevron
        if (item.type == MenuItemType::Submenu) {
            render_chevron(ctx, item_x + menu_width - ContextMenu::PADDING_H - ContextMenu::CHEVRON_SIZE,
                          item_y, is_disabled);
        } else if (item.shortcut) {
            // Left-align all shortcuts to same X position based on longest shortcut
            float shortcut_x = item_x + menu_width - ContextMenu::PADDING_H - max_shortcut_width;
            D2D1_RECT_F shortcut_rect = D2D1::RectF(
                shortcut_x,
                text_y,
                item_x + menu_width - ContextMenu::PADDING_H,
                text_y + item.item_height
            );

            uint32_t shortcut_color = is_disabled ? ContextMenu::TEXT_DISABLED : ContextMenu::TEXT_SHORTCUT;
            ctx.draw_text(item.shortcut, wcslen(item.shortcut), g_text_format_body, shortcut_rect, shortcut_color);
        }
    }

    void render_checkmark(RenderContext& ctx, float x, float y) {
        float cx = x + ContextMenu::ICON_COLUMN_WIDTH / 2.0f;
        float cy = y + ContextMenu::ITEM_HEIGHT / 2.0f;
        float scale = ContextMenu::CHECKMARK_SIZE / 16.0f;

        D2D1_POINT_2F p1 = D2D1::Point2F(cx - 4.0f * scale, cy);
        D2D1_POINT_2F p2 = D2D1::Point2F(cx - 0.5f * scale, cy + 3.0f * scale);
        D2D1_POINT_2F p3 = D2D1::Point2F(cx + 4.0f * scale, cy - 3.0f * scale);

        ctx.brush->SetColor(color_from_argb(ContextMenu::CHECKMARK));
        ctx.target->DrawLine(p1, p2, ctx.brush, 1.5f);
        ctx.target->DrawLine(p2, p3, ctx.brush, 1.5f);
    }

    void render_chevron(RenderContext& ctx, float x, float y, bool disabled) {
        float cy = y + ContextMenu::ITEM_HEIGHT / 2.0f;
        float size = 4.0f;

        uint32_t color = disabled ? ContextMenu::TEXT_DISABLED : ContextMenu::TEXT_SHORTCUT;
        ctx.brush->SetColor(color_from_argb(color));
        ctx.target->DrawLine(D2D1::Point2F(x, cy - size),
                            D2D1::Point2F(x + size, cy), ctx.brush, 1.0f);
        ctx.target->DrawLine(D2D1::Point2F(x + size, cy),
                            D2D1::Point2F(x, cy + size), ctx.brush, 1.0f);
    }

    void open_submenu(int item_index) {
        if (item_index < 0 || static_cast<size_t>(item_index) >= item_count) return;
        MenuItem& item = items[item_index];
        if (item.type != MenuItemType::Submenu || !item.submenu_items) return;

        // Close existing submenu if different
        if (submenu_parent_index != item_index) {
            close_submenu();
        }
        if (active_submenu) return;  // Already open

        // Create submenu widget
        active_submenu = g_widget_arena.create<ContextMenuWidget>();
        active_submenu->parent_menu = this;
        active_submenu->is_submenu = true;  // Mark for faster animation timing

        // Position: right edge of parent item, same Y
        float sub_x = menu_x + menu_width + ContextMenu::SUBMENU_OFFSET_X;
        float sub_y = menu_y + item.item_y;

        active_submenu->show(sub_x, sub_y, item.submenu_items, item.submenu_item_count);
        submenu_parent_index = item_index;
    }

    void close_submenu() {
        if (active_submenu) {
            active_submenu->close_submenu();  // Recursive close
            // If the submenu is still mid-animation, balance the scheduler
            // count it registered via animation_started() in show()/hide().
            // Without this, force-closing a submenu mid-animation leaks an
            // active_count and pins the render loop on forever.
            if (active_submenu->anim_state == AnimState::Opening ||
                active_submenu->anim_state == AnimState::Closing) {
                g_animation_scheduler.animation_ended();
            }
            active_submenu->visible = false;
            active_submenu->flags &= ~WidgetFlags::Visible;
            active_submenu->anim_state = AnimState::Closed;
            active_submenu->release_blur_cache();
            active_submenu = nullptr;
        }
        submenu_parent_index = -1;
    }

    void activate_item(int index) {
        if (index < 0 || static_cast<size_t>(index) >= item_count) return;
        MenuItem& item = items[index];

        if (!item.enabled) return;
        if (item.type == MenuItemType::Separator) return;
        if (item.type == MenuItemType::Submenu) return;  // Submenu opened on hover

        // Toggle checkbox
        if (item.type == MenuItemType::Checkbox) {
            item.checked = !item.checked;
        }

        // Fire callback
        if (item.on_click) {
            item.on_click(&item, item.user_data);
        }

        // Close entire menu tree
        ContextMenuWidget* root = this;
        while (root->parent_menu) root = root->parent_menu;
        root->hide();
    }

    int find_next_enabled_item(int from, int direction) {
        if (item_count == 0) return -1;

        int start = from;
        if (start < 0) {
            start = (direction > 0) ? -1 : static_cast<int>(item_count);
        }

        int current = start;
        for (size_t i = 0; i < item_count; i++) {
            current += direction;

            // Wrap around
            if (current < 0) current = static_cast<int>(item_count) - 1;
            if (current >= static_cast<int>(item_count)) current = 0;

            if (items[current].type != MenuItemType::Separator && items[current].enabled) {
                return current;
            }
        }

        return -1;  // No enabled items found
    }
};

// ============================================================================
// Global Context Menu State
// ============================================================================

static ContextMenuWidget* g_active_context_menu = nullptr;

// Show a context menu at the specified position
static void context_menu_show(float x, float y, MenuItem* items, size_t count,
                              void (*on_dismiss)(ContextMenuWidget*, void*) = nullptr,
                              void* user_data = nullptr) {
    // Close any existing menu
    if (g_active_context_menu && g_active_context_menu->visible) {
        g_active_context_menu->force_close_immediate(true);
    }

    // Create new menu
    g_active_context_menu = g_widget_arena.create<ContextMenuWidget>();
    g_active_context_menu->on_dismiss = on_dismiss;
    g_active_context_menu->dismiss_user_data = user_data;
    g_active_context_menu->show(x, y, items, count);
}

// Hide the active context menu (API for programmatic dismissal)
[[maybe_unused]] static void context_menu_hide() {
    if (g_active_context_menu && g_active_context_menu->visible) {
        g_active_context_menu->hide();
    }
}

// Check if a context menu is visible
static bool context_menu_is_visible() {
    return g_active_context_menu && g_active_context_menu->visible;
}

// Render the active context menu (call from main render loop)
static void context_menu_render(RenderContext& ctx) {
    if (!g_active_context_menu || !g_active_context_menu->visible) return;

    // Render the menu and all submenus
    ContextMenuWidget* menu = g_active_context_menu;
    while (menu) {
        menu->render(ctx);
        menu = menu->active_submenu;
    }
}

// Dispatch mouse events to context menu (returns true if consumed)
static bool context_menu_dispatch_mouse_move(float x, float y) {
    if (!g_active_context_menu || !g_active_context_menu->visible) return false;

    // Check submenus first (deepest first)
    ContextMenuWidget* menu = g_active_context_menu;
    while (menu->active_submenu) {
        menu = menu->active_submenu;
    }

    // Walk back up, checking each menu
    while (menu) {
        float local_x = x - menu->menu_x;
        float local_y = y - menu->menu_y;

        if (local_x >= 0 && local_y >= 0 &&
            local_x < menu->menu_width && local_y < menu->menu_height) {
            menu->on_mouse_move(local_x, local_y);
            return true;
        }

        // Clear hover on menus we're not over
        if (menu->hovered_index >= 0 && !menu->active_submenu) {
            menu->hovered_index = -1;
            menu->set_dirty();
        }

        menu = menu->parent_menu;
    }

    return true;  // Still consume to prevent underlying UI interaction
}

static bool context_menu_dispatch_mouse_down(float x, float y, int button) {
    if (!g_active_context_menu || !g_active_context_menu->visible) return false;

    // Find which menu (if any) was clicked
    ContextMenuWidget* menu = g_active_context_menu;
    while (menu->active_submenu) {
        menu = menu->active_submenu;
    }

    while (menu) {
        float local_x = x - menu->menu_x;
        float local_y = y - menu->menu_y;

        if (local_x >= 0 && local_y >= 0 &&
            local_x < menu->menu_width && local_y < menu->menu_height) {
            menu->on_mouse_down(local_x, local_y, button);
            return true;
        }

        menu = menu->parent_menu;
    }

    // Click outside all menus - close
    g_active_context_menu->hide();
    return true;
}

static bool context_menu_dispatch_mouse_up(float x, float y, int button) {
    if (!g_active_context_menu || !g_active_context_menu->visible) return false;

    // Find which menu has the pressed state
    ContextMenuWidget* menu = g_active_context_menu;
    while (menu->active_submenu) {
        menu = menu->active_submenu;
    }

    while (menu) {
        if (menu->pressed_index >= 0) {
            float local_x = x - menu->menu_x;
            float local_y = y - menu->menu_y;
            menu->on_mouse_up(local_x, local_y, button);
            return true;
        }
        menu = menu->parent_menu;
    }

    return true;
}

static bool context_menu_dispatch_key_down(int vk, bool ctrl, bool shift, bool alt) {
    if (!g_active_context_menu || !g_active_context_menu->visible) return false;

    // Send to deepest active submenu first
    ContextMenuWidget* menu = g_active_context_menu;
    while (menu->active_submenu) {
        menu = menu->active_submenu;
    }

    return menu->on_key_down(vk, ctrl, shift, alt);
}
